from typing import List
from collections import defaultdict

class Solution:
    def minimumSeconds(self, nums: List[int]) -> int:
        n = len(nums)
        if n == 0:
            return 0
        if all(x == nums[0] for x in nums):
            return 0

        positions = defaultdict(list)
        for i, num in enumerate(nums):
            positions[num].append(i)

        max_distance = 0
        for num, indices in positions.items():
            for i in range(1, len(indices)):
                distance = (indices[i] - indices[i - 1] - 1 + n) % n
                max_distance = max(max_distance, distance)
            # Also check the wrap-around distance between last and first
            distance = (indices[0] + n - indices[-1] - 1) % n
            max_distance = max(max_distance, distance)

        return (max_distance + 1) // 2
